ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?projects a :Projects .
    ?assignments a :Assignments .
    ?assignments p:hasProjects ?projects .
    ?scriptwriters a :Scriptwriters .
    ?assignments p:hasScriptwriters ?scriptwriters .
    ?scriptwriters p:name ?name .
    ?projects p:Deadline ?deadline_f .
    FILTER(STR(?deadline_f) = "2021-05-10")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?projects a :Projects .
    ?assignments a :Assignments .
    ?assignments p:hasProjects ?projects .
    ?editors a :Editors .
    ?assignments p:hasEditors ?editors .
    ?editors p:name ?name .
    ?projects p:Deadline ?deadline_f .
    FILTER(STR(?deadline_f) = "2021-05-10")
    BIND(?name AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?projects a :Projects .
    ?assignments a :Assignments .
    ?assignments p:hasProjects ?projects .
    ?scriptwriters a :Scriptwriters .
    ?assignments p:hasScriptwriters ?scriptwriters .
    ?scriptwriters p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?projects a :Projects .
    ?assignments a :Assignments .
    ?assignments p:hasProjects ?projects .
    ?editors a :Editors .
    ?assignments p:hasEditors ?editors .
    ?editors p:name ?name .
    ?projects p:Deadline ?deadline_f .
    FILTER(STR(?deadline_f) = "2021-05-10")
    BIND(?name AS ?o0)
  }
} }
}
